import { describe, it, expect } from "vitest";
// Implementation lives in ./claim-office.js (logic) and ../src/cli.ts (CLI).
// import { ... } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: base premiums (R1) ---
  it.todo("empty item list → premium 5 G (processing fee only)");
  it.todo("single sword → premium 105 G (100 base + 5 fee), neutral customer");
  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("single staff → premium 85 G (80 base + 5 fee)");
  it.todo("single potion → premium 45 G (40 base + 5 fee)");
  it.todo("single rune component → premium 30 G (25 base + 5 fee)");

  // --- Quote: component block (R2) ---
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block of exactly 3)");
  it.todo("4 runes → 100 G base premium (no block; block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (7×25; not exactly 3, all singles)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (different types, no block)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks of 60)");

  // --- Quote: item-specific modifiers (R3) ---
  it.todo("cursed sword → curse adds 50% of item base (100 → +50 base premium)");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge +30% applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment ≥5 → both curse and high-enchantment surcharges apply");

  // --- Quote: policy-wide modifiers (R3) ---
  it.todo("customer with exactly 2 years → 20% loyalty discount applies to policy base");
  it.todo("first insurance → +10% surcharge per item base premium");
  it.todo("second quote in scenario → 15% follow-up discount applies policy-wide");

  // --- Quote: modifier scope on multi-item policies (R3) ---
  it.todo("cursed sword (base 100) + plain amulet (base 60) → 210 G before fee (curse on sword base only)");

  // --- Quote: integration examples (R3) ---
  it.todo("newcomer (0 years) cursed sword steel ench 3 → premium 165 G (100+50 curse+10 first +5 fee)");
  it.todo("3-year customer 2nd quote, cursed sword steel ench 7 → premium 160 G (100+50+30-20+10-15+5)");

  // --- Quote: rounding (R4) ---
  it.todo("premium yielding 197.5 G → final premium 198 G (rounded up)");

  // --- Claim: standard reimbursement (R5) ---
  it.todo("steel sword ench 3, damage 500 → payout 400 G (full minus 100 deductible)");
  it.todo("rune (value 250), damage 200 → payout 100 G (no clause; minus 100 deductible)");

  // --- Claim: deductible per damage event (R5) ---
  it.todo("dragon attack damages sword (500) + amulet (300) → payout 600 G (deductible per item)");

  // --- Claim: enchantment threshold vs dragon material (R5) ---
  it.todo("dragon sword ench exactly 8, damage 1000 → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon sword ench 9, damage 1000 → payout 400 G (both clauses, 50% wins: 500−100)");
  it.todo("dragon sword ench 5, damage 800 → payout 700 G (dragon clause only: 800−100)");
  it.todo("steel sword ench 9, damage 1000 → payout 400 G (high-enchantment only: 500−100)");

  // --- Claim: payout rounding (R4) ---
  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Claim: cap (R5) ---
  it.todo("policy sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (modified premium 165 G) → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy sword + 3 runes (block) → insurance sum 1750 G (block affects premium only, not sum)");
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("sword (cap 2000), first claim 1500 → payout 1400 G, remainingCap 600 G");
  it.todo("sword (cap 2000), second successive claim 1500 → payout 600 G (capped), remainingCap 0 G");

  // --- CLI surface (R7) ---
  it.todo("CLI reads JSON scenario from stdin and writes {results:[...]} to stdout");
  it.todo("CLI processes quote then claim sequentially; claim references policy by zero-based index");

  // --- CLI error cases (R6) ---
  it.todo("CLI: quote with unknown item type (broomstick) → non-zero exit, error to stderr, no results on stdout");
  it.todo("CLI: claim references item not in policy (amulet, only sword insured) → non-zero exit + stderr");
  it.todo("CLI: claim damage amount -200 → non-zero exit + stderr");
  it.todo("CLI: more damage entries of a type than insured (2 sword damages, 1 sword) → non-zero exit, claim rejected");
});
